import { useEffect, useRef } from "react";
import {
  createFileRoute,
  linkOptions,
  redirect,
  useNavigate,
} from "@tanstack/react-router";
import {
  useDeactivateCommitment,
  useGetCommitmentQueryOptions,
} from "@workspace/api-client/public";
import { Card, CardContent, CardDescription, CardHeader } from "@workspace/ui";
import { Loader2 } from "lucide-react";
import { z } from "zod";
import { queryClient } from "../../../lib/query-client";

const searchSchema = z.object({
  t: z.string().min(1, "Token is required"),
});

export const Route = createFileRoute(
  "/token-auth/commitment/$commitmentId/cancel",
)({
  component: RouteComponent,
  validateSearch: searchSchema,
  loaderDeps: ({ search: { t } }) => ({ t }),
  loader: async ({ params, deps: { t } }) => {
    const reactivateLinkOptions = linkOptions({
      params: { commitmentId: params.commitmentId },
      search: { t },
      to: "/token-auth/commitment/$commitmentId/reactivate",
    });

    const cancelationReasonLinkOptions = linkOptions({
      params: { commitmentId: params.commitmentId },
      search: { t },
      to: "/token-auth/commitment/$commitmentId/cancelation-reason",
    });

    const commitment = await queryClient.fetchQuery(
      useGetCommitmentQueryOptions({
        commitmentId: params.commitmentId,
        t,
      }),
    );

    if (commitment.active === false) {
      throw redirect(reactivateLinkOptions);
    }

    return {
      commitmentId: params.commitmentId,
      cancelationReasonLinkOptions,
    };
  },
});

function RouteComponent() {
  const { commitmentId, cancelationReasonLinkOptions } = Route.useLoaderData();
  const { t } = Route.useSearch();
  const navigate = useNavigate();
  const hasDeactivated = useRef(false);

  const {
    mutate: deactivateCommitment,
    isPending,
    isSuccess,
  } = useDeactivateCommitment({
    onError: () => console.error("Unable to deactivate commitment"),
    onSuccess: () => navigate(cancelationReasonLinkOptions),
  });

  useEffect(() => {
    if (!isPending && !isSuccess && !hasDeactivated.current) {
      hasDeactivated.current = true;
      deactivateCommitment({
        commitmentId,
        t,
      });
    }
  }, [commitmentId, t, deactivateCommitment, isSuccess, isPending]);

  return (
    <div className="flex overflow-auto flex-col gap-6 items-center px-2 py-4 w-screen h-screen bg-slate-50 xs:py-12">
      <img
        alt="Anedot"
        className="w-full max-w-[120px] mx-auto"
        src="/anedot_typemark_light.svg"
      />
      <Card className="mx-auto w-full max-w-[512px]">
        <CardHeader>
          <CardDescription>Canceling your commitment</CardDescription>
        </CardHeader>
        <CardContent className="flex flex-col gap-8 justify-center items-center">
          {isPending ? (
            <Loader2 className="w-16 h-16 animate-spin text-primary" />
          ) : null}
        </CardContent>
      </Card>
    </div>
  );
}

